// Collections Framework hierarchy (conceptual diagram)
// Iterable<E>
//   └── Collection<E>
//         ├── List<E>      ... ArrayList, LinkedList
//         ├── Set<E>       ... HashSet, TreeSet, LinkedHashSet
//         └── Queue<E>     ... ArrayDeque, PriorityQueue
//               └── Deque<E> ... ArrayDeque
//
// Map<K,V> (independent)   ... HashMap, TreeMap, LinkedHashMap

Collection<String> col = new ArrayList<>();
col.add("A");
col.add("B");
System.out.println(col.size());  // 2

List<String> list = new ArrayList<>(List.of("A", "B", "C"));

// for-each statement (internally uses Iterator)
for (String s : list) {
    System.out.println(s);
}

// Safe removal using Iterator
Iterator<String> it = list.iterator();
while (it.hasNext()) {
    String s = it.next();
    if (s.equals("B")) {
        it.remove();  // Can be safely removed
    }
}
System.out.println(list);  // [A, C]

// Note: remove during for-each is NOT allowed
// for (String s : list) {
//     list.remove(s);  // ConcurrentModificationException!
// }

Collection<String> c = new ArrayList<>();
c.add("X");
c.add("Y");
c.add("Z");

System.out.println(c.contains("Y"));  // true
System.out.println(c.size());          // 3
System.out.println(c.isEmpty());       // false

c.remove("Y");
System.out.println(c);  // [X, Z]

// Bulk operations
Collection<String> other = List.of("Z", "W");
c.addAll(other);       // [X, Z, Z, W]
c.retainAll(other);    // [Z, Z, W] (keeps only elements contained in other)

List<String> list = List.of("A", "B", "C");

// for-each statement
