// List.of() — Creating an immutable list
List<String> immutable = List.of("A", "B", "C");
// immutable.add("D");  // UnsupportedOperationException
// immutable.set(0, "X");  // UnsupportedOperationException

// List.copyOf() — Creating an immutable list from an existing collection
List<String> original = new ArrayList<>(List.of("X", "Y"));
List<String> copy = List.copyOf(original);
original.add("Z");  // original is mutable
System.out.println(copy);  // [X, Y] (copy is not affected)

// null elements are not allowed
// List.of("A", null);  // NullPointerException

List<String> list = new ArrayList<>(List.of("A", "B", "C"));
ListIterator<String> li = list.listIterator();

// Forward traversal
while (li.hasNext()) {
    int idx = li.nextIndex();
    String s = li.next();
    System.out.println(idx + ": " + s);  // 0: A, 1: B, 2: C
}

// Reverse traversal
while (li.hasPrevious()) {
    String s = li.previous();
    System.out.println(s);  // C, B, A
}

