Set<String> hashSet = new HashSet<>();
hashSet.add("Banana");
hashSet.add("Apple");
hashSet.add("Cherry");
hashSet.add("Apple");  // Duplicate → not added (returns false)

System.out.println(hashSet.size());  // 3
System.out.println(hashSet);  // Order is undefined (e.g., [Cherry, Apple, Banana])

// null elements can also be stored
hashSet.add(null);
System.out.println(hashSet.contains(null));  // true

// TreeSet — Maintains sorted order
Set<String> treeSet = new TreeSet<>();
treeSet.add("Banana");
treeSet.add("Apple");
treeSet.add("Cherry");
System.out.println(treeSet);  // [Apple, Banana, Cherry] (natural order)

TreeSet<Integer> nums = new TreeSet<>(Set.of(5, 2, 8, 1, 9));
System.out.println(nums.first());    // 1
System.out.println(nums.last());     // 9
System.out.println(nums.floor(6));   // 5 (greatest element <= 6)
System.out.println(nums.ceiling(6)); // 8 (smallest element >= 6)

// LinkedHashSet — Preserves insertion order
Set<String> linkedSet = new LinkedHashSet<>();
linkedSet.add("Banana");
linkedSet.add("Apple");
linkedSet.add("Cherry");
System.out.println(linkedSet);  // [Banana, Apple, Cherry] (insertion order)

public class Student {
    private String name;
    private int id;

    // If you override equals(), you must also override hashCode()
    @Override
    public boolean equals(Object o) {
        if (this == o) return true;
        if (!(o instanceof Student)) return false;
        Student s = (Student) o;
        return id == s.id && Objects.equals(name, s.name);
    }

    @Override
    public int hashCode() {
        return Objects.hash(name, id);
    }
}

// With correct implementation, duplicates are eliminated in HashSet
Set<Student> set = new HashSet<>();
set.add(new Student("Taro", 1));
set.add(new Student("Taro", 1));  // Not added because equals() returns true
System.out.println(set.size());  // 1

// Set.of() — Creating an immutable Set
Set<String> immutableSet = Set.of("A", "B", "C");
// immutableSet.add("D");  // UnsupportedOperationException

// Passing duplicate elements throws IllegalArgumentException
// Set.of("A", "B", "A");  // IllegalArgumentException

// Set.copyOf()
List<String> list = List.of("X", "Y", "X");
Set<String> copySet = Set.copyOf(list);  // Duplicates are removed
System.out.println(copySet.size());  // 2

