Queue<String> queue = new ArrayDeque<>();

// Adding elements
queue.offer("A");
queue.offer("B");
queue.offer("C");
System.out.println(queue);  // [A, B, C]

// Examining the head element (without removing)
System.out.println(queue.peek());  // A
System.out.println(queue.size());  // 3

// Removing the head element
System.out.println(queue.poll());  // A
System.out.println(queue.poll());  // B
System.out.println(queue);         // [C]

// Operations on an empty queue
queue.clear();
System.out.println(queue.poll());     // null
System.out.println(queue.peek());     // null
// queue.remove();  // NoSuchElementException
// queue.element(); // NoSuchElementException

// Using as a queue (FIFO)
Deque<String> queue = new ArrayDeque<>();
queue.offerLast("A");   // Add to the tail
queue.offerLast("B");
queue.offerLast("C");
System.out.println(queue.pollFirst());  // A (remove from the head)
System.out.println(queue.pollFirst());  // B

// Using as a stack (LIFO)
Deque<String> stack = new ArrayDeque<>();
stack.push("X");  // Add to the head (= offerFirst)
stack.push("Y");
stack.push("Z");
System.out.println(stack.pop());  // Z (remove from the head = pollFirst)
System.out.println(stack.pop());  // Y
System.out.println(stack.peek()); // X (examine only = peekFirst)

// PriorityQueue with natural order (ascending)
PriorityQueue<Integer> pq = new PriorityQueue<>();
pq.offer(30);
pq.offer(10);
pq.offer(20);

System.out.println(pq.peek());  // 10 (minimum value)
System.out.println(pq.poll());  // 10
System.out.println(pq.poll());  // 20
System.out.println(pq.poll());  // 30

// PriorityQueue in descending order (with Comparator)
PriorityQueue<Integer> descPq = new PriorityQueue<>(Comparator.reverseOrder());
descPq.offer(30);
descPq.offer(10);
descPq.offer(20);
System.out.println(descPq.poll());  // 30 (maximum value)

