// Comparable — Defining natural order
public class Student implements Comparable<Student> {
    String name;
    int score;

    public Student(String name, int score) {
        this.name = name;
        this.score = score;
    }

    @Override
    public int compareTo(Student other) {
        return Integer.compare(this.score, other.score);  // Ascending by score
    }
}

// Comparator — Custom order
Comparator<Student> byName = (s1, s2) -> s1.name.compareTo(s2.name);
Comparator<Student> byScoreDesc = (s1, s2) -> Integer.compare(s2.score, s1.score);

List<Student> students = new ArrayList<>();
Collections.sort(students);         // Comparable order (ascending by score)
Collections.sort(students, byName); // Comparator order (by name)

// Concise notation using Comparator.comparing()
Comparator<Student> byName = Comparator.comparing(s -> s.name);
Comparator<Student> byScore = Comparator.comparingInt(s -> s.score);

// Sorting with multiple conditions (descending by score → ascending by name)
Comparator<Student> comp = Comparator
    .comparingInt((Student s) -> s.score).reversed()
    .thenComparing(s -> s.name);

List<Student> students = new ArrayList<>();
students.add(new Student("Taro", 85));
students.add(new Student("Hanako", 92));
students.add(new Student("Jiro", 85));
students.sort(comp);
// Result: Hanako(92), Jiro(85), Taro(85)

List<String> list = new ArrayList<>(List.of("C", "A", "B"));

// Sorting in natural order with List.sort()
list.sort(Comparator.naturalOrder());
System.out.println(list);  // [A, B, C]

// Sorting in reverse order
list.sort(Comparator.reverseOrder());
System.out.println(list);  // [C, B, A]

// Sorting a list containing nulls
List<String> withNull = new ArrayList<>(Arrays.asList("B", null, "A"));
withNull.sort(Comparator.nullsFirst(Comparator.naturalOrder()));
System.out.println(withNull);  // [null, A, B]

withNull.sort(Comparator.nullsLast(Comparator.naturalOrder()));
System.out.println(withNull);  // [A, B, null]

